// ============================================================
// Contract Utilities
// ============================================================

const CONTRACT_CHECK = typeof process !== "undefined"
  ? process.env.VDM_CONTRACT_CHECK !== "off"
  : true;

class ContractError extends Error {
  constructor(message: string) {
    super(`[Contract Violation] ${message}`);
    this.name = "ContractError";
  }
}

function checkPre(condition: boolean, message: string): void {
  if (CONTRACT_CHECK && !condition) {
    throw new ContractError(`Pre-condition failed: ${message}`);
  }
}

function checkPost(condition: boolean, message: string): void {
  if (CONTRACT_CHECK && !condition) {
    throw new ContractError(`Post-condition failed: ${message}`);
  }
}

function checkInv(condition: boolean, message: string): void {
  if (CONTRACT_CHECK && !condition) {
    throw new ContractError(`Invariant violated: ${message}`);
  }
}

// ============================================================
// Types
// ============================================================

/** VDM-SL: TaskId = nat1 */
type TaskId = number;

/** VDM-SL: Priority = <Low> | <Medium> | <High> */
type Priority = "Low" | "Medium" | "High";

/** VDM-SL: Status = <Todo> | <InProgress> | <Done> */
type Status = "Todo" | "InProgress" | "Done";

/**
 * VDM-SL Record: Task
 * inv t == len t.title <= 100 and len t.desc <= 500
 */
interface Task {
  readonly id: TaskId;
  readonly title: string;
  readonly desc: string;
  readonly status: Status;
  readonly priority: Priority;
  readonly assignee: string | null;
}

/** Invariant check: Task */
function invTask(t: Task): boolean {
  return (
    t.title.length > 0 &&
    t.title.length <= 100 &&
    t.desc.length <= 500
  );
}

/** Factory function: mk_Task with invariant check */
function mkTask(
  id: TaskId,
  title: string,
  desc: string,
  status: Status,
  priority: Priority,
  assignee: string | null
): Task {
  checkPre(id >= 1, `TaskId must be nat1, got ${id}`);
  checkPre(title.length > 0, `title must be seq1 of char (non-empty)`);
  const task: Task = { id, title, desc, status, priority, assignee };
  checkInv(invTask(task), `Task invariant: title.len<=100, desc.len<=500 — got title.len=${title.length}, desc.len=${desc.length}`);
  return task;
}

/** VDM-SL: TaskBoard = map TaskId to Task */
type TaskBoard = Map<TaskId, Task>;

/** Invariant check: TaskBoard — forall id in set dom board & board(id).id = id */
function invTaskBoard(board: TaskBoard): boolean {
  for (const [id, task] of board) {
    if (task.id !== id) return false;
  }
  return true;
}

// ============================================================
// Functions (pure)
// ============================================================

/**
 * VDM-SL: ValidTransition(fromSt, toSt) ==
 *   if fromSt = toSt then true
 *   else if fromSt = <Done> then false
 *   else true
 */
function validTransition(fromSt: Status, toSt: Status): boolean {
  if (fromSt === toSt) return true;
  if (fromSt === "Done") return false;
  return true;
}

/** VDM-SL: FilterByStatus(board, s) */
function filterByStatus(board: TaskBoard, s: Status): Set<Task> {
  const result = new Set<Task>();
  for (const [, task] of board) {
    if (task.status === s) result.add(task);
  }
  return result;
}

/** VDM-SL: FilterByPriority(board, p) */
function filterByPriority(board: TaskBoard, p: Priority): Set<Task> {
  const result = new Set<Task>();
  for (const [, task] of board) {
    if (task.priority === p) result.add(task);
  }
  return result;
}

/** VDM-SL: CountByStatus(board, s) */
function countByStatus(board: TaskBoard, s: Status): number {
  let count = 0;
  for (const [, task] of board) {
    if (task.status === s) count++;
  }
  return count;
}

/** VDM-SL: GetAssignedTasks(board, person) */
function getAssignedTasks(board: TaskBoard, person: string): Set<Task> {
  const result = new Set<Task>();
  for (const [, task] of board) {
    if (task.assignee === person) result.add(task);
  }
  return result;
}

// ============================================================
// State
// ============================================================

/**
 * VDM-SL State: TaskManagerState
 * inv mk_TaskManagerState(board, nextId) ==
 *   (forall id in set dom board & id < nextId) and nextId >= 1
 * init s == s = mk_TaskManagerState({|->}, 1)
 */
class TaskManagerState {
  board: TaskBoard;
  nextId: TaskId;

  constructor() {
    this.board = new Map();
    this.nextId = 1;
    this.checkStateInvariant();
  }

  private checkStateInvariant(): void {
    checkInv(this.nextId >= 1, `State invariant: nextId >= 1, got ${this.nextId}`);
    for (const id of this.board.keys()) {
      checkInv(id < this.nextId, `State invariant: id ${id} must be < nextId ${this.nextId}`);
    }
    checkInv(invTaskBoard(this.board), `State invariant: TaskBoard invariant failed`);
  }

  // ============================================================
  // Operations
  // ============================================================

  /**
   * VDM-SL: CreateTask(title, desc, priority, assignee) ==> TaskId
   * pre: len title <= 100 and len desc <= 500
   * post: RESULT = nextId~ - 1 and RESULT in set dom board
   *       and board(RESULT).title = title and board(RESULT).status = <Todo>
   */
  createTask(title: string, desc: string, priority: Priority, assignee: string | null): TaskId {
    // Pre-conditions
    checkPre(title.length > 0, `title must be non-empty`);
    checkPre(title.length <= 100, `title length must be <= 100, got ${title.length}`);
    checkPre(desc.length <= 500, `desc length must be <= 500, got ${desc.length}`);

    const oldNextId = this.nextId;
    const newId: TaskId = this.nextId;
    const newTask = mkTask(newId, title, desc, "Todo", priority, assignee);
    this.board.set(newId, newTask);
    this.nextId = this.nextId + 1;

    // Post-conditions
    checkPost(newId === oldNextId, `RESULT should equal old nextId`);
    checkPost(this.board.has(newId), `RESULT must be in dom board`);
    checkPost(this.board.get(newId)!.title === title, `board(RESULT).title must equal title`);
    checkPost(this.board.get(newId)!.status === "Todo", `board(RESULT).status must be Todo`);

    this.checkStateInvariant();
    return newId;
  }

  /**
   * VDM-SL: ChangeStatus(taskId, newStatus) ==> ()
   * pre: taskId in set dom board and ValidTransition(board(taskId).status, newStatus)
   * post: board(taskId).status = newStatus and board(taskId).title = board~(taskId).title
   */
  changeStatus(taskId: TaskId, newStatus: Status): void {
    // Pre-conditions
    checkPre(this.board.has(taskId), `taskId ${taskId} not in dom board`);
    const oldTask = this.board.get(taskId)!;
    checkPre(
      validTransition(oldTask.status, newStatus),
      `Invalid transition: ${oldTask.status} → ${newStatus}`
    );

    const oldTitle = oldTask.title;
    const updated = mkTask(oldTask.id, oldTask.title, oldTask.desc, newStatus, oldTask.priority, oldTask.assignee);
    this.board.set(taskId, updated);

    // Post-conditions
    checkPost(this.board.get(taskId)!.status === newStatus, `status must be ${newStatus}`);
    checkPost(this.board.get(taskId)!.title === oldTitle, `title must be preserved`);

    this.checkStateInvariant();
  }

  /**
   * VDM-SL: UpdateTask(taskId, title, desc, priority, assignee) ==> ()
   * pre: taskId in set dom board and len title <= 100 and len desc <= 500
   * post: board(taskId).title = title and board(taskId).status = board~(taskId).status
   */
  updateTask(taskId: TaskId, title: string, desc: string, priority: Priority, assignee: string | null): void {
    // Pre-conditions
    checkPre(this.board.has(taskId), `taskId ${taskId} not in dom board`);
    checkPre(title.length > 0, `title must be non-empty`);
    checkPre(title.length <= 100, `title length must be <= 100`);
    checkPre(desc.length <= 500, `desc length must be <= 500`);

    const oldTask = this.board.get(taskId)!;
    const oldStatus = oldTask.status;
    const updated = mkTask(oldTask.id, title, desc, oldTask.status, priority, assignee);
    this.board.set(taskId, updated);

    // Post-conditions
    checkPost(this.board.get(taskId)!.title === title, `title must be updated`);
    checkPost(this.board.get(taskId)!.status === oldStatus, `status must be preserved`);

    this.checkStateInvariant();
  }

  /**
   * VDM-SL: DeleteTask(taskId) ==> ()
   * pre: taskId in set dom board
   * post: taskId not in set dom board and card dom board = card dom board~ - 1
   */
  deleteTask(taskId: TaskId): void {
    // Pre-condition
    checkPre(this.board.has(taskId), `taskId ${taskId} not in dom board`);

    const oldSize = this.board.size;
    this.board.delete(taskId);

    // Post-conditions
    checkPost(!this.board.has(taskId), `taskId must not be in dom board after delete`);
    checkPost(this.board.size === oldSize - 1, `board size must decrease by 1`);

    this.checkStateInvariant();
  }

  /**
   * VDM-SL: GetSummary() ==> nat * nat * nat
   * post: let mk_(t, i, d) = RESULT in t + i + d = card dom board
   */
  getSummary(): [number, number, number] {
    const t = countByStatus(this.board, "Todo");
    const i = countByStatus(this.board, "InProgress");
    const d = countByStatus(this.board, "Done");

    // Post-condition
    checkPost(t + i + d === this.board.size, `summary counts must equal board size`);

    return [t, i, d];
  }
}

